function attachSlotDragAndDrop(p,rerender){let dragged=null;const clear=()=>document.querySelectorAll('.base-slot').forEach(x=>x.classList.remove('drag-source','drag-target'));document.querySelectorAll('.base-slot.occupied[draggable="true"]').forEach(card=>{card.ondragstart=e=>{dragged=p.placed.find(x=>x.source===Number(card.dataset.source)&&x.unit===Number(card.dataset.unit));if(!dragged){e.preventDefault();return}card.classList.add('drag-source');e.dataTransfer.effectAllowed='move';e.dataTransfer.setData('text/plain',`${dragged.source}:${dragged.unit}`)};card.ondragend=()=>{dragged=null;clear()}});document.querySelectorAll('.base-slot[data-slot-index]').forEach(target=>{target.ondragover=e=>{if(!dragged||target.disabled)return;e.preventDefault();e.dataTransfer.dropEffect='move';target.classList.add('drag-target')};target.ondragleave=()=>target.classList.remove('drag-target');target.ondrop=e=>{e.preventDefault();if(!dragged||target.disabled)return;const station=target.dataset.slotStation||target.dataset.station,index=Number(target.dataset.slotIndex);if(station===dragged.station&&index===dragged.slot){clear();return}const occupant=p.placed.find(x=>x.station===station&&x.slot===index);movePlacedDroid(p,dragged,station,index,occupant);dragged=null;clear();rerender()}})}
const norm=s=>s.toUpperCase().replace(/[^A-Z0-9]/g,'');
function imageFor(droid,variant='DEFAULT'){
  const aliases={'BU-4D':'B-U4D','LO':'L0','BB':'BB8','OPTI-STRIKE':'OPTI-STRK','SENATE HOVERCAM':'SENATE HOVERCAM'}; const target=norm(aliases[droid.name]||droid.name);
  const entries=Object.entries(state.images).filter(([k])=>norm(k.split(' - Droid')[0].replace(/\((Gold|Diamond|Rainbow|Beskar)\)/i,''))===target);
  let match=entries.find(([k])=>variant==='DEFAULT'?!/\((Gold|Diamond|Rainbow|Beskar)\)/i.test(k):new RegExp(`\\(${variant}\\)`,'i').test(k));
  match ||= entries.find(([k])=>!/\((Gold|Diamond|Rainbow|Beskar)\)/i.test(k)) || entries[0]; return match?.[1]||'';
}
function picture(droid,variant='DEFAULT'){const src=imageFor(droid,variant);return src?`<img src="${src}" alt="${droid.name} ${variant.toLowerCase()} variant" loading="lazy">`:`<span class="fallback">${droid.name.slice(0,3)}</span>`}
function card(d){return `<a class="droid-card ${d.rarity.toLowerCase()}" href="#/droid/${slug(d.name)}"><div class="droid-image">${picture(d)}</div><div class="card-body"><span class="badge">${d.rarity}</span><h3>${d.name}</h3><div class="card-meta"><span>${d.type}</span><span class="card-income">${isIconic(d)?`${iconicIncome(d)*100}%/s`:`${fmt(d.variants.DEFAULT.income)}/s`}</span></div></div></a>`}
const patchNotesSeenKey='droid-archive-seen-patch-notes';
const patchTodoTasks=()=>state.patchNotes.filter(x=>x.todo).map(x=>({id:x.todo.id||x.id,text:x.todo.text||x.title,done:x.todo.done??true,patchNote:true,date:x.date}));
function seenPatchNoteIds(){try{return JSON.parse(localStorage.getItem(patchNotesSeenKey)||'[]')}catch{return[]}}
function markPatchNotesSeen(notes){const seen=new Set(seenPatchNoteIds());notes.forEach(note=>seen.add(note.id));localStorage.setItem(patchNotesSeenKey,JSON.stringify([...seen]))}
function showPatchNotesOnce(){if(patchNotesPrompted||!state.patchNotes.length)return;const seen=new Set(seenPatchNoteIds()),notes=state.patchNotes.filter(note=>note.showOnStartup!==false&&!seen.has(note.id));if(!notes.length)return;patchNotesPrompted=true;const root=document.querySelector('#modalRoot');root.innerHTML=`<div class="modal-backdrop patch-notes-backdrop"><section class="modal patch-notes-modal" role="dialog" aria-modal="true" aria-labelledby="patchNotesTitle"><p class="eyebrow">Droid Archives update</p><h2 id="patchNotesTitle">What's new?</h2><div class="patch-notes-list">${notes.map(note=>`<article><header><strong>${note.title}</strong>${note.date?`<time>${note.date}</time>`:''}</header>${note.summary?`<p>${note.summary}</p>`:''}${Array.isArray(note.changes)&&note.changes.length?`<ul>${note.changes.map(change=>`<li>${change}</li>`).join('')}</ul>`:''}</article>`).join('')}</div><div class="modal-actions"><button class="btn" id="patchNotesClose">Got it</button><a class="btn secondary" href="#/todo" id="patchNotesTodo">View To Do List</a></div></section></div>`;const close=()=>{markPatchNotesSeen(notes);root.innerHTML=''};root.querySelector('#patchNotesClose').onclick=close;root.querySelector('#patchNotesTodo').onclick=close}
function droidexEntry(name,variant){return state.droidex.find(x=>x.name===name&&x.variant===variant)}
function toggleDroidex(name,variant){const index=state.droidex.findIndex(x=>x.name===name&&x.variant===variant);index>=0?state.droidex.splice(index,1):state.droidex.push({name,variant,flawless:isDroidFlawless(name)});save()}
function toggleFlawless(name,variant){const d=state.droids.find(x=>x.name===name);if(isIconic(d)||!droidexEntry(name,variant))return;const flawless=!isDroidFlawless(name);state.droidex.filter(x=>x.name===name).forEach(x=>x.flawless=flawless);save()}
function addDetailDroidexControls(){if(!location.hash.startsWith('#/droid/')||document.querySelector('.detail-actions'))return;const add=document.querySelector('#addThis');if(!add)return;const d=state.droids.find(x=>slug(x.name)===location.hash.split('/')[2]);const active=document.querySelector('.variant-tabs button.active');if(!d)return;const variant=isIconic(d)?'DEFAULT':active?.dataset.v||'DEFAULT',entry=droidexEntry(d.name,variant),flawless=isDroidFlawless(d.name);add.insertAdjacentHTML('afterend',`<div class="detail-actions"><button class="btn secondary" id="toggleDex">${entry?'Remove from':'Add to'} Droidex</button>${isIconic(d)?'':`<button class="flawless-toggle ${flawless?'active':''}" id="toggleFlawless" ${entry?'':'disabled'}>✦ ${flawless?'Flawless':'Mark flawless'}</button>`}</div>`);document.querySelector('#toggleDex').onclick=()=>{toggleDroidex(d.name,variant);toast(entry?'Removed from Droidex':'Added to Droidex');document.querySelector('.detail-actions').remove();addDetailDroidexControls()};const flawlessButton=document.querySelector('#toggleFlawless');if(flawlessButton)flawlessButton.onclick=()=>{toggleFlawless(d.name,variant);document.querySelector('.detail-actions').remove();addDetailDroidexControls()}}
function droidexPage(){let variant='DEFAULT';const render=()=>{const collected=state.droidex.filter(x=>x.variant===variant).length,flawless=flawlessCount();app.innerHTML=`<div class="breadcrumbs"><a href="#/">Homepage</a> / Droidex</div><section class="dex-hero"><div><p class="eyebrow">Collection tracker</p><h1>Droidex</h1><p>Collect every droid quality and mark your flawless finds.</p></div><div class="dex-totals"><strong>${state.droidex.length}/${state.droids.length*VARIANTS.length}</strong><span>✦ ${flawless}/${flawlessCapacity()} flawless tracked</span><button class="btn secondary" id="transferDroidex">⇄ Import / Export</button></div></section><div class="variant-tabs dex-tabs">${VARIANTS.map(v=>`<button data-dex-variant="${v}" class="${v===variant?'active':''}">${v[0]+v.slice(1).toLowerCase()}</button>`).join('')}</div><div class="dex-toolbar"><input id="dexSearch" class="form-control" placeholder="Search Droidex…"><label><input id="dexMissing" type="checkbox"> Missing only</label><span>${collected}/${state.droids.length} ${variant.toLowerCase()} collected</span></div><div id="dexGrid" class="dex-grid"></div>`;const draw=()=>{const q=document.querySelector('#dexSearch').value.toLowerCase(),missing=document.querySelector('#dexMissing').checked;const list=state.droids.filter(d=>d.name.toLowerCase().includes(q)&&(!missing||!droidexEntry(d.name,variant)));document.querySelector('#dexGrid').innerHTML=list.map(d=>{const entry=droidexEntry(d.name,variant),flawless=isDroidFlawless(d.name);return `<article class="dex-card ${entry?'collected':'missing'} ${flawless?'flawless':''}"><a href="#/droid/${slug(d.name)}">${picture(d,variant)}<span class="badge">${d.rarity}</span><strong>${d.name}</strong></a><div><button class="dex-own" data-dex-own="${d.name}">${entry?'✓ Owned':'+ Add'}</button><button class="dex-flawless" data-dex-flawless="${d.name}" ${entry?'':'disabled'}>✦ ${flawless?'Flawless':'Flawless?'}</button></div></article>`}).join('');document.querySelectorAll('[data-dex-own]').forEach(b=>b.onclick=()=>{toggleDroidex(b.dataset.dexOwn,variant);render()});document.querySelectorAll('[data-dex-flawless]').forEach(b=>b.onclick=()=>{toggleFlawless(b.dataset.dexFlawless,variant);render()})};document.querySelectorAll('[data-dex-variant]').forEach(b=>b.onclick=()=>{variant=b.dataset.dexVariant;render()});document.querySelector('#transferDroidex').onclick=()=>showDroidexTransferModal(render);document.querySelector('#dexSearch').oninput=draw;document.querySelector('#dexMissing').onchange=draw;draw()};render()}
function home(){const featured=[...state.droids].sort(()=>Math.random()-.5).slice(0,4);app.innerHTML=`<section class="hero"><p class="eyebrow">Community knowledgebase</p><h1>Droid Tycoon, decoded.</h1><p class="lead">Browse every droid and variant, compare production, then build your collection and see exactly which droids to keep for later rebirths.</p></section><div class="quick-grid"><a class="quick-card" href="#/droids"><b>Explore all ${state.droids.length} droids →</b><p>Costs, income, rarity, type, attributes and every quality.</p></a><a class="quick-card" href="#/base"><b>Build your base →</b><p>Add owned droids and calculate live, minute and hourly credits.</p></a></div><h2>Featured droids</h2><div class="droid-grid">${featured.map(card).join('')}</div><h2>About this archive</h2><p class="lead">This is an unofficial companion for the Fortnite island <strong>Droid Tycoon</strong>. Your base is saved only in this browser. The visual language takes cues from classic game wikis: compact facts, readable tables and information-first pages.</p>`}
const novaUpgrade=id=>state.novaShop?.upgrades?.find(x=>x.id===id);
const novaCost=(level=0)=>`<img src="${state.novaShop?.currency?.icon||'assets/events/nova-crystal.png'}" alt=""> ${fmt(level.cost)}`;
function scrapSeconds(){const config=state.novaShop?.calculators?.scrap,upgrade=novaUpgrade(config?.upgradeId||'scrap-value'),level=novaLevelFor(config?.upgradeId||'scrap-value');return upgrade&&level?Number(upgrade.levels[level-1]?.scrapSeconds??config?.defaultSeconds??1):0}
function scrapCalculatorHtml(placed){const config=state.novaShop?.calculators?.scrap;if(!config)return'';const income=scrapIncomeForPlaced(placed),seconds=scrapSeconds(),level=novaLevelFor(config.upgradeId),drops=config.drops||[];return `<section class="scrap-calculator"><div><p class="eyebrow">Workshop calculator</p><h2>${config.title||'Scrap calculator'}</h2><p>${config.description||''}</p><small>Scrap Value level ${level} · ${seconds||'—'} second${seconds===1?'':'s'} of current Base generation · Scrap base ${fmt(income)}/s</small></div><table><thead><tr><th>Scrap</th>${drops.map(drop=>`<th>${drop.name}</th>`).join('')}</tr></thead><tbody>${(config.qualities||[]).map(row=>`<tr><th>${row.name}</th>${drops.map((drop,i)=>`<td>${seconds?fmt(income*seconds*Number(row.multipliers?.[i]??1)):'—'}</td>`).join('')}</tr>`).join('')}</tbody></table></section>`}
function setNovaLevel(id,level){const upgrade=novaUpgrade(id);if(!upgrade)return;const max=upgrade.levels.length;state.novaUpgrades[id]=Math.max(0,Math.min(max,Number(level)||0));if(id==='lounge-slot')state.loungePurchased=state.novaUpgrades[id];save();toast(`${upgrade.name} set to level ${state.novaUpgrades[id]}`)}
function novaShopPage(){let category='all';const render=()=>{const shop=state.novaShop;if(!shop){app.innerHTML='<h1>Nova Shop unavailable</h1>';return}const p=placements(),list=shop.upgrades.filter(x=>category==='all'||x.category===category);app.innerHTML=`<div class="breadcrumbs"><a href="#/">Homepage</a> / Nova Shop</div><section class="nova-hero"><div><p class="eyebrow">Nova upgrades</p><h1>Nova Shop</h1><p class="lead">Track Nova Crystal upgrades, costs, and unlocks. Upgrade levels are saved with your profile.</p></div><div class="nova-currency"><img src="${shop.currency.icon}" alt=""><strong>${shop.currency.name}s</strong></div></section>${scrapCalculatorHtml(p.placed)}<div class="variant-tabs nova-tabs"><button data-nova-cat="all" class="${category==='all'?'active':''}">All</button>${shop.categories.map(c=>`<button data-nova-cat="${c.id}" class="${category===c.id?'active':''}">${c.name}</button>`).join('')}</div><div class="nova-grid">${list.map(u=>{const level=novaLevelFor(u.id),next=u.levels[level],done=level>=u.levels.length;return `<article class="nova-card"><a href="#/nova-shop/${u.id}"><span class="nova-card-icon">${u.icon}</span><small>${shop.categories.find(c=>c.id===u.category)?.name||u.category}</small><strong>${u.name}</strong><em>${level}/${u.levels.length}</em><p>${u.description}</p></a><div><button class="btn secondary" data-nova-dec="${u.id}" ${level<=0?'disabled':''}>−</button><span>${done?'Maxed':novaCost(next)}</span><button class="btn" data-nova-inc="${u.id}" ${done?'disabled':''}>+</button></div></article>`}).join('')}</div><h2>Nova crystals from rebirths</h2><table class="nova-reward-table"><thead><tr><th>Rebirth</th><th>Nova Crystals</th><th>Credit Mult</th><th>XP Mult</th></tr></thead><tbody>${shop.rebirthRewards.map(r=>`<tr><td>RB ${r.rebirth}</td><td>${r.novaCrystals}</td><td>${r.creditMultPercent}%</td><td>${r.xpMultPercent}%</td></tr>`).join('')}</tbody></table>`;document.querySelectorAll('[data-nova-cat]').forEach(b=>b.onclick=()=>{category=b.dataset.novaCat;render()});document.querySelectorAll('[data-nova-inc]').forEach(b=>b.onclick=()=>{setNovaLevel(b.dataset.novaInc,novaLevelFor(b.dataset.novaInc)+1);render()});document.querySelectorAll('[data-nova-dec]').forEach(b=>b.onclick=()=>{setNovaLevel(b.dataset.novaDec,novaLevelFor(b.dataset.novaDec)-1);render()})};render()}
function novaDetailPage(id){const u=novaUpgrade(id);if(!u){notFound();return}const category=state.novaShop.categories.find(c=>c.id===u.category)?.name||u.category,level=novaLevelFor(u.id),total=u.levels.reduce((s,x)=>s+x.cost,0),spent=u.levels.slice(0,level).reduce((s,x)=>s+x.cost,0);app.innerHTML=`<div class="breadcrumbs"><a href="#/">Homepage</a> / <a href="#/nova-shop">Nova Shop</a> / ${u.name}</div><div class="article-grid"><article><p class="eyebrow">${category}</p><h1>${u.name}</h1><p class="lead">${u.description}</p><div class="base-top"><div class="stat"><small>Current level</small><strong>${level}/${u.levels.length}</strong></div><div class="stat"><small>Spent</small><strong>${fmt(spent)}</strong></div><div class="stat"><small>Total cost</small><strong>${fmt(total)}</strong></div><div class="stat"><small>Next cost</small><strong>${u.levels[level]?fmt(u.levels[level].cost):'Maxed'}</strong></div></div><h2>Upgrade costs</h2><table><thead><tr><th>Level</th><th>Nova Crystal cost</th><th>Running total</th></tr></thead><tbody>${u.levels.map((x,i)=>`<tr class="${i<level?'selected-variant':''}"><td>${x.level}</td><td>${novaCost(x)}</td><td>${fmt(u.levels.slice(0,i+1).reduce((s,y)=>s+y.cost,0))}</td></tr>`).join('')}</tbody></table><div class="modal-actions"><button class="btn secondary" id="novaDown" ${level<=0?'disabled':''}>Decrease level</button><button class="btn" id="novaUp" ${level>=u.levels.length?'disabled':''}>Increase level</button></div></article><aside class="infobox nova-info"><div class="info-title">${u.name}</div><div class="nova-big-icon">${u.icon}</div><div class="info-rows"><div class="info-row"><b>Category</b><span>${category}</span></div><div class="info-row"><b>Level</b><span>${level}/${u.levels.length}</span></div><div class="info-row"><b>Currency</b><span>${state.novaShop.currency.name}</span></div><div class="info-row"><b>Source</b><span>Nova Shop</span></div></div></aside></div>`;document.querySelector('#novaUp').onclick=()=>{setNovaLevel(u.id,level+1);novaDetailPage(id)};document.querySelector('#novaDown').onclick=()=>{setNovaLevel(u.id,level-1);novaDetailPage(id)}}
function droidsPage(){const q=new URLSearchParams(location.hash.split('?')[1]||'');app.innerHTML=`<div class="breadcrumbs"><a href="#/">Main page</a> / Droids</div><p class="eyebrow">Droidex</p><h1>All droids</h1><p class="lead">The complete archive. Select a droid for its dedicated page and all five quality variants.</p><div class="toolbar"><input id="droidSearch" placeholder="Filter by name…"><select id="typeFilter"><option value="">All types</option>${['WORKER','ASTROMECH','BATTLE'].map(x=>`<option ${q.get('type')===x?'selected':''}>${x}</option>`).join('')}</select><select id="rarityFilter"><option value="">All rarities</option>${['COMMON','RARE','EPIC','LEGENDARY','MYTHIC','ICONIC'].map(x=>`<option>${x}</option>`).join('')}</select></div><p id="resultCount" class="eyebrow"></p><div id="droidGrid" class="droid-grid"></div>`;const draw=()=>{let name=document.querySelector('#droidSearch').value.toLowerCase(),type=document.querySelector('#typeFilter').value,rarity=document.querySelector('#rarityFilter').value;let list=state.droids.filter(d=>d.name.toLowerCase().includes(name)&&(!type||d.type===type)&&(!rarity||d.rarity===rarity));document.querySelector('#resultCount').textContent=`${list.length} entries`;document.querySelector('#droidGrid').innerHTML=list.map(card).join('')};['droidSearch','typeFilter','rarityFilter'].forEach(id=>document.querySelector('#'+id).addEventListener('input',draw));draw()}
function detailPage(id){const d=state.droids.find(x=>slug(x.name)===id);if(!d){notFound();return}let variant='DEFAULT';const render=()=>{const v=d.variants[variant];app.innerHTML=`<div class="breadcrumbs"><a href="#/">Main page</a> / <a href="#/droids">Droids</a> / ${d.name}</div><div class="article-grid"><article><p class="eyebrow">${d.rarity} ${d.type} droid</p><h1>${d.name}</h1><p class="lead"><strong>${d.name}</strong> is a ${d.rarity.toLowerCase()} ${d.type.toLowerCase()} droid. Its base form produces ${fmt(d.variants.DEFAULT.income)} credits per second and every quality is catalogued below.</p><div class="variant-tabs">${VARIANTS.map(x=>`<button data-v="${x}" class="${variant===x?'active':''}">${x[0]+x.slice(1).toLowerCase()}</button>`).join('')}</div><h2>${variant[0]+variant.slice(1).toLowerCase()} statistics</h2><table><thead><tr><th>Variant</th><th>Crafting cost</th><th>Credits / second</th><th>Credits / hour</th></tr></thead><tbody><tr class="selected-variant"><td><strong>${variant[0]+variant.slice(1).toLowerCase()}</strong></td><td>${fmt(v.cost)}</td><td>${fmt(v.income)}</td><td>${fmt(v.income*3600)}</td></tr></tbody></table><h2>Gameplay</h2><p class="lead">As a ${d.type.toLowerCase()} droid, ${d.name} provides <strong>${ATTRIBUTE[d.type]}</strong>. Production shown in the table is before your in-game credit multiplier.</p><button class="btn" id="addThis">Add ${variant.toLowerCase()} to my base</button> <button class="btn secondary" id="addBlueprintThis">Add blueprint</button></article><aside class="infobox"><div class="info-title">${d.name}</div><div class="info-image">${picture(d,variant)}</div><div class="info-rows"><div class="info-row"><b>Quality</b><span>${variant}</span></div><div class="info-row"><b>Rarity</b><span>${d.rarity}</span></div><div class="info-row"><b>Type</b><span>${d.type}</span></div><div class="info-row"><b>Attribute</b><span>${ATTRIBUTE[d.type]}</span></div><div class="info-row"><b>Cost</b><span>${fmt(v.cost)} credits</span></div><div class="info-row"><b>Income</b><span>${fmt(v.income)}/s</span></div></div></aside></div>`;document.querySelectorAll('[data-v]').forEach(b=>b.onclick=()=>{variant=b.dataset.v;render()});document.querySelector('#addThis').onclick=()=>requestAdd(d.name,variant);document.querySelector('#addBlueprintThis').onclick=()=>addBlueprint(d.name,variant)};render()}
function commitOwned(name,variant,qty=1,preferred,preferredSlot){const slot=Number(preferredSlot),hasSlot=Number.isInteger(slot),row=state.owned.find(x=>x.name===name&&x.variant===variant&&x.preferred===preferred&&(!hasSlot||Number(x.preferredSlot)===slot));row?row.qty+=qty:state.owned.push({name,variant,qty,...(preferred?{preferred,...(hasSlot?{preferredSlot:slot}:{})}:{})});save();toast(`${name} added to your base`)}
function addBlueprint(name,variant,slot){const used=new Set(state.blueprints.map(x=>Number(x.slot))),target=Number.isInteger(Number(slot))?Number(slot):Array.from({length:capacity('BLUEPRINT_STORAGE')},(_,i)=>i).find(i=>!used.has(i));if(target===undefined||target<0||target>=capacity('BLUEPRINT_STORAGE')){toast('No Blueprint Storage slot available');return}state.blueprints.push({name,variant,slot:target});save();toast(`${name} blueprint stored`)}
function craftBlueprint(index,onDone){const blueprint=state.blueprints[index];if(!blueprint)return;const occupied=new Set(placements().placed.filter(x=>x.station==='BUILD').map(x=>x.slot)),slot=Array.from({length:capacity('BUILD')},(_,i)=>i).find(i=>!occupied.has(i));if(slot===undefined){toast('No free Build slot');return}state.blueprints.splice(index,1);state.owned.push({name:blueprint.name,variant:blueprint.variant,qty:1,preferred:'BUILD',preferredSlot:slot});save();toast(`${blueprint.name} moved to Build`);onDone?.()}
function requestAdd(name,variant,qty=1,onDone){const d=state.droids.find(x=>x.name===name),p=placements();const available=capacity(d.type)-p.placed.filter(x=>x.station===d.type).length+capacity('BUILD')-p.placed.filter(x=>x.station==='BUILD').length;if(available>=qty){commitOwned(name,variant,qty);onDone?.();return}showCapacityModal({name,variant,qty,onDone})}
function showCapacityModal(pending){const root=document.querySelector('#modalRoot');const candidates=expandedOwned();root.innerHTML=`<div class="modal-backdrop"><section class="modal" role="dialog" aria-modal="true"><p class="eyebrow">Base capacity reached</p><h2>No compatible slots are free</h2><p><strong>${pending.name}</strong> needs a matching type slot or one of the universal Build slots.</p><div class="modal-actions"><button class="btn" id="chooseSwap">Swap a droid</button><button class="btn secondary" id="forceAdd">Force add</button><button class="btn ghost" id="cancelAdd">Cancel</button></div><div id="swapChooser"></div></section></div>`;root.querySelector('#cancelAdd').onclick=()=>root.innerHTML='';root.querySelector('#forceAdd').onclick=()=>{commitOwned(pending.name,pending.variant,pending.qty);root.innerHTML='';pending.onDone?.()};root.querySelector('#chooseSwap').onclick=()=>{root.querySelector('#swapChooser').innerHTML=`<label class="field swap-field">Choose the droid to replace<select id="swapTarget" class="form-control">${candidates.map((x,i)=>`<option value="${x.source}">${x.name} · ${x.variant}</option>`).join('')}</select></label><button class="btn" id="confirmSwap">Confirm swap</button>`;root.querySelector('#confirmSwap').onclick=()=>{const index=Number(root.querySelector('#swapTarget').value),row=state.owned[index];row.qty>1?row.qty--:state.owned.splice(index,1);commitOwned(pending.name,pending.variant,pending.qty);root.innerHTML='';pending.onDone?.()}}}
function basePage(){
  const cycles=Object.keys(state.rebirths);
  const slotCard=(type,index,p)=>{const occupant=p.placed.find(x=>x.station===type&&x.slot===index);if(occupant){const d=state.droids.find(x=>x.name===occupant.name);return `<a class="base-slot occupied" href="#/droid/${slug(d.name)}"><div>${picture(d,occupant.variant)}</div><strong>${d.name}</strong><small>${occupant.variant} · ${fmt(d.variants[occupant.variant].income*state.multiplier)}/s</small></a>`}const rule=SLOT_RULES[type],unlock=rule.unlocks[index-rule.initial],isLocked=unlock>state.rebirth;return `<div class="base-slot ${isLocked?'locked':'open'}"><span class="slot-icon">${type==='BUILD'?'⚒':`<img src="${TYPE_IMAGES[type]}" alt="">`}</span><small>${isLocked?`Unlocks at Rebirth ${unlock}`:`${type[0]+type.slice(1).toLowerCase()} slot`}</small></div>`};
  const station=(type,p)=>{const total=SLOT_RULES[type].initial+SLOT_RULES[type].unlocks.length;const active=capacity(type);const used=p.placed.filter(x=>x.station===type).length;return `<section class="station station-${type.toLowerCase()}"><header><span>${type==='BUILD'?'⚒':`<img src="${TYPE_IMAGES[type]}" alt="">`}<strong>${type[0]+type.slice(1).toLowerCase()}</strong></span><small>${used}/${active} slots${total-active?` · ${total-active} future`:''}</small></header><div class="slot-grid">${Array.from({length:total},(_,i)=>slotCard(type,i,p)).join('')}</div></section>`};
  const render=()=>{const p=placements();const income=state.owned.reduce((sum,x)=>{const d=state.droids.find(y=>y.name===x.name);return sum+(d?.variants[x.variant]?.income||0)*x.qty},0)*state.multiplier;const future=(state.rebirths[state.cycle]||[]).filter(r=>r.to>state.rebirth).flatMap(r=>r.requiredDroids.map(req=>({...req,at:r.to})));const futureRows=future.map(req=>{const have=state.owned.some(x=>x.name===req.droidName&&x.variant===req.variant&&x.qty>0);return `<div class="future-item ${have?'have':'missing'}"><b>Rebirth ${req.at}</b><span>${req.variant} <a href="#/droid/${slug(req.droidName)}">${req.droidName}</a></span><span>${have?'✓ In base':'Needed'}</span></div>`}).join('');const roster=state.owned.map((x,i)=>{const d=state.droids.find(y=>y.name===x.name);return `<div class="roster-row"><a href="#/droid/${slug(d.name)}">${picture(d,x.variant)}<span><strong>${d.name}</strong><small>${x.variant} · ×${x.qty}</small></span></a><button class="icon-btn remove" data-i="${i}" title="Remove">×</button></div>`}).join('');
    app.innerHTML=`<div class="breadcrumbs"><a href="#/">Main page</a> / My base</div><div class="base-heading"><div><p class="eyebrow">Personal planner</p><h1>My base</h1></div><button class="btn" id="openAdd">+ Add droid</button></div><div class="base-top"><div class="stat"><small>Credits / second</small><strong>${fmt(income)}</strong></div><div class="stat"><small>Credits / minute</small><strong>${fmt(income*60)}</strong></div><div class="stat"><small>Credits / hour</small><strong>${fmt(income*3600)}</strong></div><div class="stat"><small>Droids owned</small><strong>${state.owned.reduce((s,x)=>s+x.qty,0)}</strong></div></div><section class="panel base-controls"><label class="field">Credit multiplier<input class="form-control" id="multiplier" type="number" min="0" step="0.1" value="${state.multiplier}"></label><label class="field">Super rebirth cycle<select class="form-control" id="cycle">${cycles.map(c=>`<option value="${c}" ${Number(c)===state.cycle?'selected':''}>Cycle ${Number(c)+1}</option>`).join('')}</select></label><label class="field">Current rebirth<select class="form-control" id="rebirth">${Array.from({length:28},(_,n)=>`<option ${n===state.rebirth?'selected':''}>${n}</option>`).join('')}</select></label></section><div class="base-workspace"><div class="station-board">${['WORKER','ASTROMECH','BATTLE','BUILD'].map(t=>station(t,p)).join('')}</div><aside class="roster"><header><strong>Roster</strong><span>${state.owned.reduce((s,x)=>s+x.qty,0)}</span></header>${p.overflow.length?`<div class="overflow-warning">${p.overflow.length} force-added droid${p.overflow.length>1?'s are':' is'} over capacity.</div>`:''}<div>${roster||'<p class="roster-empty">No droids yet. Add one to fill a station.</p>'}</div></aside></div><h2>Needed later in this cycle</h2><div class="notice">Green entries are already in your roster. Requirements begin after your selected current rebirth.</div><div class="future-list">${futureRows||'<div class="empty">Nothing else is required in this cycle.</div>'}</div>`;
    document.querySelector('#multiplier').onchange=e=>{state.multiplier=Number(e.target.value)||0;save();render()};document.querySelector('#cycle').onchange=e=>{state.cycle=Number(e.target.value);save();render()};document.querySelector('#rebirth').onchange=e=>{state.rebirth=Number(e.target.value);save();render()};document.querySelector('#openAdd').onclick=()=>showAddModal(render);document.querySelectorAll('.remove').forEach(b=>b.onclick=()=>{state.owned.splice(Number(b.dataset.i),1);save();render()})};render()}
function showAddModal(onDone){const root=document.querySelector('#modalRoot');root.innerHTML=`<div class="modal-backdrop"><section class="modal" role="dialog" aria-modal="true"><p class="eyebrow">Roster</p><h2>Add a droid</h2><div class="modal-form"><label class="field">Droid<select id="addName" class="form-control">${state.droids.map(d=>`<option>${d.name}</option>`).join('')}</select></label><label class="field">Variant<select id="addVariant" class="form-control">${VARIANTS.map(v=>`<option>${v}</option>`).join('')}</select></label><label class="field">Quantity<input id="addQty" class="form-control" type="number" min="1" value="1"></label></div><div class="modal-actions"><button class="btn" id="confirmAdd">Add to base</button><button class="btn ghost" id="cancelAdd">Cancel</button></div></section></div>`;root.querySelector('#cancelAdd').onclick=()=>root.innerHTML='';root.querySelector('#confirmAdd').onclick=()=>{const data={name:root.querySelector('#addName').value,variant:root.querySelector('#addVariant').value,qty:Math.max(1,Number(root.querySelector('#addQty').value)||1)};root.innerHTML='';requestAdd(data.name,data.variant,data.qty,onDone)}}
function futureRequirements(){return(state.rebirths[state.cycle]||[]).filter(r=>r.to>state.rebirth).flatMap(r=>r.requiredDroids.map(req=>({...req,at:r.to})))}
function requirementState(name){const req=futureRequirements().find(x=>x.droidName===name);if(!req)return null;const owned=state.owned.filter(x=>x.name===name);const enough=owned.some(x=>VARIANTS.indexOf(x.variant)>=VARIANTS.indexOf(req.variant));return{...req,enough}}
function luckyEligible(d){return d&&!isIconic(d)&&luckyChance(d)>0}
function luckyOwnedUnits(){const p=placements(),placed=new Map(p.placed.map(x=>[`${x.source}:${x.unit}`,x]));return expandedOwned().map(unit=>{const d=state.droids.find(x=>x.name===unit.name);return{...unit,droid:d,placement:placed.get(`${unit.source}:${unit.unit}`)}}).filter(x=>luckyEligible(x.droid)&&VARIANTS.indexOf(x.variant)<VARIANTS.indexOf('BESKAR'))}
function luckyCreditGain(unit,target='BESKAR'){const d=unit.droid,baseNow=d.variants[unit.variant]?.income||0,baseTarget=d.variants[target]?.income||0,p=placements(),productive=p.placed.filter(x=>!['BUILD','LOUNGE','COMPANION'].includes(x.station)),iconicRate=[...new Set(productive.map(x=>x.name))].reduce((sum,name)=>sum+iconicIncome(state.droids.find(d=>d.name===name)),0),placement=unit.placement,station=placement&&!['BUILD','LOUNGE','COMPANION'].includes(placement.station)?placement.station:d.type,output=(station===d.type?1.1:1)+iconicRate;return Math.max(0,(baseTarget-baseNow)*output*effectiveMultiplier())}
function luckyRecommendations(mode='rebirth'){const reqs=futureRequirements(),bestByName=new Map();for(const unit of luckyOwnedUnits()){const previous=bestByName.get(unit.name);if(!previous||VARIANTS.indexOf(unit.variant)>VARIANTS.indexOf(previous.variant))bestByName.set(unit.name,unit)}return[...bestByName.values()].map(unit=>{const d=unit.droid,chance=luckyChance(d),needed=reqs.filter(r=>r.droidName===d.name&&VARIANTS.indexOf(r.variant)>VARIANTS.indexOf(unit.variant));if(mode==='rebirth'){if(!needed.length)return null;const target=needed.reduce((best,r)=>VARIANTS.indexOf(r.variant)>VARIANTS.indexOf(best.variant)?r:best,needed[0]),nextAt=Math.min(...needed.map(r=>r.at)),chips=chipsToVariant(d,unit.variant,target.variant),expectedChips=chips*chance,urgency=1/Math.max(1,nextAt-state.rebirth),score=expectedChips*(1+urgency*4),gain=luckyCreditGain(unit,target.variant),expectedGain=gain*chance;return{mode,unit,droid:d,target:target.variant,score,chance,chips,expectedChips,gain,expectedGain,nextAt,rebirths:[...new Set(needed.map(r=>r.at))],reason:`Needed at rebirth ${nextAt}. A ${luckyChanceLabel(d)} Lucky success saves ${fmt(chips)} upgrade chips toward ${variantLabel(target.variant)} (${fmt(expectedChips)} expected chips per attempt).`}}const gain=luckyCreditGain(unit,'BESKAR'),chips=chipsToVariant(d,unit.variant,'BESKAR'),expectedGain=gain*chance,expectedChips=chips*chance;return{mode,unit,droid:d,target:'BESKAR',score:expectedGain,chance,chips,expectedChips,gain,expectedGain,nextAt:null,rebirths:reqs.filter(r=>r.droidName===d.name).map(r=>r.at),reason:`Beskar would add about ${fmt(gain)}/s, or ${fmt(gain*3600)}/h, from your current multiplier and likely productive placement. At ${luckyChanceLabel(d)}, that is ${fmt(expectedGain*3600)}/h expected value per attempt.`}}).filter(Boolean).filter(x=>x.score>0).sort((a,b)=>b.score-a.score).slice(0,5)}
function luckyDroidPage(){let mode='rebirth',selected=0;const render=()=>{const list=luckyRecommendations(mode),pick=list[selected]||list[0];app.innerHTML=`<div class="breadcrumbs"><a href="#/">Homepage</a> / Lucky Droid Recommendation</div><section class="lucky-hero"><p class="eyebrow">Daily gamble helper</p><h1>Lucky Droid Recommendation</h1><p class="lead">Every 24 hours you can gamble a Lucky Droid upgrade up to Beskar quality. Success chance depends on rarity: Common 32%, Rare 16%, Epic 8%, Legendary 4%, Mythic 2%. These recommendations factor that chance into the score.</p><div class="variant-tabs lucky-tabs"><button data-lucky-mode="rebirth" class="${mode==='rebirth'?'active':''}">Rebirth based</button><button data-lucky-mode="credit" class="${mode==='credit'?'active':''}">Credit based</button></div></section>${list.length?`<div class="lucky-layout"><div class="lucky-list">${list.map((item,i)=>`<button class="lucky-card ${i===selected?'active':''}" data-lucky-pick="${i}"><span>${i+1}</span><div>${picture(item.droid,item.unit.variant)}</div><strong>${item.droid.name}</strong><small>${variantLabel(item.unit.variant)} → ${variantLabel(item.target)} · ${luckyChanceLabel(item.droid)}</small><em>${mode==='rebirth'?`${fmt(item.expectedChips)} expected chips`:`+${fmt(item.expectedGain*3600)}/h expected`}</em></button>`).join('')}</div><article class="lucky-detail"><div class="article-grid"><article><p class="eyebrow">${mode==='rebirth'?'Rebirth priority':'Credit priority'}</p><h2>${pick.droid.name}</h2><p class="lead">${pick.reason}</p><table><tbody><tr><th>Current</th><td>${variantLabel(pick.unit.variant)}</td></tr><tr><th>Lucky target</th><td>${variantLabel(pick.target)}</td></tr><tr><th>Success chance</th><td>${luckyChanceLabel(pick.droid)} per daily attempt</td></tr><tr><th>Upgrade chips saved</th><td>${fmt(pick.chips)} on success · ${fmt(pick.expectedChips)} expected</td></tr><tr><th>Credit gain</th><td>+${fmt(pick.gain)}/s · +${fmt(pick.gain*3600)}/h on success · +${fmt(pick.expectedGain*3600)}/h expected</td></tr>${pick.rebirths.length?`<tr><th>Future rebirth use</th><td>R: ${[...new Set(pick.rebirths)].join(', ')}</td></tr>`:''}</tbody></table><h3>Why this is good</h3><p>${mode==='rebirth'?`This mode favours droids that remove the most expected upgrade-chip pressure from upcoming rebirth requirements, with earlier rebirths weighted higher.`:`This mode favours the largest expected production gain after applying the rarity success chance.`}</p></article><aside class="infobox"><div class="info-title">${pick.droid.name}</div><div class="info-image">${picture(pick.droid,pick.target)}</div><div class="info-rows"><div class="info-row"><b>Type</b><span>${pick.droid.type}</span></div><div class="info-row"><b>Rarity</b><span>${pick.droid.rarity}</span></div><div class="info-row"><b>Chance</b><span>${luckyChanceLabel(pick.droid)}</span></div><div class="info-row"><b>From</b><span>${variantLabel(pick.unit.variant)}</span></div><div class="info-row"><b>To</b><span>${variantLabel(pick.target)}</span></div></div></aside></div></article></div>`:`<div class="empty">No eligible Lucky Droid recommendations yet. Add owned Common, Rare, Epic, Legendary, or Mythic droids below Beskar quality to your Base.</div>`}`;document.querySelectorAll('[data-lucky-mode]').forEach(b=>b.onclick=()=>{mode=b.dataset.luckyMode;selected=0;render()});document.querySelectorAll('[data-lucky-pick]').forEach(b=>b.onclick=()=>{selected=Number(b.dataset.luckyPick);render()})};render()}
function removeOwnedUnit(index){const row=state.owned[index];if(!row)return;row.qty>1?row.qty--:state.owned.splice(index,1);save()}
function changeOwnedUnitVariant(source,variant,station,slot){const row=state.owned[source];if(!row||row.variant===variant)return;if(row.qty>1){const changed={...row,variant,qty:1,preferred:station,preferredSlot:slot};row.qty--;if(row.preferred===station&&Number(row.preferredSlot)===slot){delete row.preferred;delete row.preferredSlot}state.owned.push(changed)}else{row.variant=variant;row.preferred=station;row.preferredSlot=slot}save()}
function showCardVariantModal(card,onDone){const root=document.querySelector('#modalRoot'),d=state.droids.find(x=>x.name===card.name);if(!d||isIconic(d))return;root.innerHTML=`<div class="modal-backdrop"><section class="modal" role="dialog" aria-modal="true"><p class="eyebrow">Change quality</p><h2>${d.name}</h2><p class="picker-hint">Choose any quality. You can upgrade or downgrade this exact card without removing it from its slot.</p><div class="variant-choice">${VARIANTS.map(v=>`<button data-card-variant="${v}" ${v===card.variant?'disabled':''}>${picture(d,v)}<strong>${variantLabel(v)}</strong><small>${v===card.variant?'Current quality':`${fmt(d.variants[v].income)}/s`}</small></button>`).join('')}</div><button class="btn ghost" id="cancelVariantChange">Cancel</button></section></div>`;root.querySelectorAll('[data-card-variant]').forEach(button=>button.onclick=()=>{changeOwnedUnitVariant(card.source,button.dataset.cardVariant,card.station,card.slot);root.innerHTML='';onDone()});root.querySelector('#cancelVariantChange').onclick=()=>root.innerHTML=''}
function showSwapModal(card,onDone){const root=document.querySelector('#modalRoot'),p=placements(),source=p.placed.find(x=>x.source===card.source&&x.unit===card.unit),occupiedKey=(station,slot)=>`${station}:${slot}`,occupied=new Set(p.placed.map(x=>occupiedKey(x.station,x.slot))),items=p.placed.filter(x=>!(x.source===card.source&&x.unit===card.unit)).map(x=>({...x,targetType:'occupied'})),emptySlots=Object.keys(SLOT_RULES).flatMap(station=>stationSlotIndices(station).filter(slot=>!occupied.has(occupiedKey(station,slot))).map(slot=>({targetType:'empty',station,slot,name:`Empty ${station} ${slot+1}`,variant:'DEFAULT'})));if(!source)return;root.innerHTML=`<div class="modal-backdrop"><section class="modal slot-picker" role="dialog" aria-modal="true"><p class="eyebrow">Manual swap</p><h2>Move ${source.name}</h2><p class="picker-hint">Choose another droid to swap with, or an empty unlocked slot to move into. Useful when drag-and-drop is awkward across the page.</p><input id="swapSearch" class="form-control picker-search" placeholder="Search droids or slots…" autofocus><div id="swapResults" class="picker-results"></div><button class="btn ghost" id="cancelSwap">Cancel</button></section></div>`;const draw=()=>{const q=root.querySelector('#swapSearch').value.toLowerCase(),targets=[...items,...emptySlots].filter(x=>x.name.toLowerCase().includes(q)||x.station.toLowerCase().includes(q)||String(x.slot+1).includes(q));root.querySelector('#swapResults').innerHTML=targets.map(x=>{if(x.targetType==='empty')return `<button class="picker-droid empty-slot-choice" data-empty-station="${x.station}" data-empty-slot="${x.slot}"><span class="slot-icon">${stationIcon(x.station)}</span><b>${x.name}</b><small>Move into empty slot</small></button>`;const d=state.droids.find(y=>y.name===x.name);return `<button class="picker-droid" data-swap-key="${x.source}:${x.unit}"><span>${picture(d,x.variant)}</span><b>${x.name}</b><small>${variantLabel(x.variant)} · ${x.station} ${x.slot+1}</small></button>`}).join('')||'<p class="roster-empty">No matching droids or empty slots.</p>';root.querySelectorAll('[data-swap-key]').forEach(b=>b.onclick=()=>{moveUnitByKey(`${source.source}:${source.unit}`,b.dataset.swapKey,onDone);root.innerHTML=''});root.querySelectorAll('[data-empty-station]').forEach(b=>b.onclick=()=>{moveUnitToSlot(`${source.source}:${source.unit}`,b.dataset.emptyStation,Number(b.dataset.emptySlot),onDone);root.innerHTML=''})};root.querySelector('#swapSearch').oninput=draw;root.querySelector('#cancelSwap').onclick=()=>root.innerHTML='';draw()}
function showSuperRebirthConfirm(rerender,really=false){const root=document.querySelector('#modalRoot'),question=really?'Are you really sure you want to super rebirth?':'Are you sure you want to super rebirth?';root.innerHTML=`<div class="modal-backdrop"><section class="modal" role="dialog" aria-modal="true" aria-labelledby="superRebirthTitle"><p class="eyebrow">Destructive action</p><h2 id="superRebirthTitle">${question}</h2><p>This will remove every droid from your base and reset its progression. This cannot be undone unless you exported your base first.</p><div class="modal-actions"><button class="btn danger" id="confirmSuperRebirth">Yes, super rebirth</button><button class="btn ghost" id="cancelSuperRebirth">Cancel</button></div></section></div>`;root.querySelector('#cancelSuperRebirth').onclick=()=>root.innerHTML='';root.querySelector('#confirmSuperRebirth').onclick=()=>{if(!really){showSuperRebirthConfirm(rerender,true);return}state.owned=[];state.multiplier=1;state.rebirth=0;state.loungePurchased=0;state.novaLevel=0;const cycleCount=Object.keys(state.rebirths).length;state.cycle=cycleCount?(state.cycle+1)%cycleCount:0;save();root.innerHTML='';toast(`Super rebirth complete · Cycle ${state.cycle+1}`);rerender()}}
function cloudDocFromCurrent(name='Main'){const id=cloudId();return{app:'Droid Archives',version:1,updatedAt:new Date().toISOString(),activeProfileId:id,ui:{theme:state.theme},profiles:[{id,name,updatedAt:new Date().toISOString(),data:profileDataFromState()}]}}
function normalizeCloudDoc(doc){doc=normalizeProfileDoc(doc);doc.ui=doc.ui||{};return doc}
function cloudDocFromLocalProfiles(){updateActiveLocalProfile();const local=ensureLocalDoc();return normalizeCloudDoc({...local,ui:{theme:state.theme}})}
const supabaseReady=()=>Boolean(supabaseConfig.url&&supabaseConfig.anonKey&&window.supabase);
const supabaseTable=()=>supabaseConfig.table||'droid_archive_profiles';
const authRedirectUrl=()=>PUBLIC_SITE_URL;
function rowToCloudDoc(row){return normalizeCloudDoc({app:'Droid Archives',version:1,updatedAt:row.updated_at,activeProfileId:row.active_profile_id,ui:row.ui||{},profiles:row.profiles||[]})}
function cloudDocToRow(){return{user_id:state.cloud.user.id,email:state.cloud.user.email||'',profiles:state.cloud.doc.profiles,active_profile_id:state.cloud.doc.activeProfileId,ui:{theme:state.theme},updated_at:new Date().toISOString()}}
async function loadSupabaseConfig(){try{const controller=new AbortController(),timer=setTimeout(()=>controller.abort(),3500);const response=await fetch(`${SUPABASE_CONFIG_PATH}?${Date.now()}`,{signal:controller.signal});clearTimeout(timer);if(response.ok){const config=await response.json();supabaseConfig={...supabaseConfig,url:config.url||'',anonKey:config.anonKey||config.anon_key||'',table:config.table||supabaseConfig.table}}}catch{}}
async function initSupabase(){if(!supabaseReady()){state.cloud.enabled=false;state.cloud.reconnecting=false;state.cloud.status='Local save';saveLocal();return}supabaseClient=window.supabase.createClient(supabaseConfig.url,supabaseConfig.anonKey,{auth:{persistSession:true,autoRefreshToken:true,detectSessionInUrl:true}});supabaseClient.auth.onAuthStateChange((event,session)=>{state.cloud.session=session;state.cloud.user=session?.user||null;if(event==='PASSWORD_RECOVERY')showPasswordUpdateModal();if(!session){state.cloud.doc=null;state.cloud.reconnecting=false;state.cloud.status='SIGNED OUT — changes save locally only';renderCloudHeader();renderBaseSidebar(()=>route());return}loadSupabaseProfiles(true).catch(e=>{state.cloud.status=e.message;renderCloudHeader()})});if(state.cloud.enabled){state.cloud.reconnecting=true;state.cloud.status='Restoring Supabase session…';renderCloudHeader();const {data}=await supabaseClient.auth.getSession();state.cloud.session=data.session;state.cloud.user=data.session?.user||null;if(state.cloud.user)await loadSupabaseProfiles(true);else{state.cloud.reconnecting=false;state.cloud.status='SIGNED OUT — sign in to sync';saveLocal()}}}
async function initSupabaseSafe(){try{await Promise.race([initSupabase(),new Promise((_,reject)=>setTimeout(()=>reject(Error('Cloud save restore timed out')),5000))])}catch(e){state.cloud.reconnecting=false;state.cloud.status='Cloud save delayed — local mode';saveLocal();renderCloudHeader()}}
async function loadSupabaseProfiles(apply=true){if(!supabaseClient||!state.cloud.user)return;state.cloud.reconnecting=false;state.cloud.status='Loading cloud profiles…';renderCloudHeader();const {data,error}=await supabaseClient.from(supabaseTable()).select('user_id,email,profiles,active_profile_id,ui,updated_at').eq('user_id',state.cloud.user.id).maybeSingle();if(error)throw Error(error.message);if(data)state.cloud.doc=rowToCloudDoc(data);else{state.cloud.doc=cloudDocFromLocalProfiles();state.cloud.activeProfileId=state.cloud.doc.activeProfileId;await writeSupabaseDoc()}state.cloud.activeProfileId=state.cloud.doc.activeProfileId;if(apply){const profile=activeCloudProfile();if(profile)applyProfileData(profile.data)}if(state.cloud.doc.ui?.theme){state.theme=state.cloud.doc.ui.theme;applyTheme()}state.cloud.enabled=true;state.cloud.reconnecting=false;state.cloud.status='Synced';saveLocal();route();renderCloudHeader()}
async function writeSupabaseDoc(){if(!supabaseClient||!state.cloud.user||!state.cloud.doc)throw Error('Supabase is not connected');state.cloud.doc.updatedAt=new Date().toISOString();state.cloud.doc.activeProfileId=state.cloud.activeProfileId;state.cloud.doc.ui={theme:state.theme};const {error}=await supabaseClient.from(supabaseTable()).upsert(cloudDocToRow(),{onConflict:'user_id'});if(error)throw Error(error.message);saveLocal()}
async function cloudSaveNow(){if(!cloudConnected())return;state.cloud.syncing=true;state.cloud.status='Syncing…';renderBaseSidebar(()=>route());renderCloudHeader();updateActiveCloudProfile();await writeSupabaseDoc();state.cloud.syncing=false;state.cloud.status='Synced';renderBaseSidebar(()=>route());renderCloudHeader();toast('Cloud save synced')}
function connectCloud(){showAuthModal('signin')}
async function signOutCloud(){if(supabaseClient)await supabaseClient.auth.signOut();state.cloud.session=null;state.cloud.user=null;state.cloud.doc=null;state.cloud.enabled=false;state.cloud.reconnecting=false;state.cloud.status='Local save';localStorage.setItem('droid-archive-sync-provider','local');toast('Signed out');route();renderCloudHeader()}
function showAuthModal(mode='signin'){const root=document.querySelector('#modalRoot');if(!supabaseReady()){root.innerHTML=`<div class="modal-backdrop"><section class="modal"><p class="eyebrow">Supabase setup</p><h2>Cloud save is not configured</h2><p>Add your Supabase URL and anon key to <code>data/supabase-config.json</code>, then refresh.</p><button class="btn ghost" id="closeAuth">Close</button></section></div>`;root.querySelector('#closeAuth').onclick=()=>root.innerHTML='';return}const isSignUp=mode==='signup',isReset=mode==='reset';root.innerHTML=`<div class="modal-backdrop"><section class="modal auth-modal"><p class="eyebrow">Supabase cloud save</p><h2>${isSignUp?'Create account':isReset?'Reset password':'Sign in'}</h2><p class="picker-hint">${isReset?'Enter your email and Supabase will send a password reset link.':'Your Droid Archives profiles sync to one row in Supabase.'}</p><label class="field">Email<input id="authEmail" class="form-control" type="email" autocomplete="email"></label>${isReset?'':`<label class="field">Password<input id="authPassword" class="form-control" type="password" autocomplete="${isSignUp?'new-password':'current-password'}"></label>`}<div class="modal-actions"><button class="btn" id="authSubmit">${isSignUp?'Create account':isReset?'Send reset email':'Sign in'}</button><button class="btn ghost" id="authCancel">Cancel</button></div><div class="auth-links">${isSignUp?'<button id="authSignin">Already have an account?</button>':'<button id="authSignup">Create account</button>'}${isReset?'':'<button id="authReset">Forgot password?</button>'}</div><p class="form-error" id="authError"></p></section></div>`;const error=root.querySelector('#authError'),submit=root.querySelector('#authSubmit');root.querySelector('#authCancel').onclick=()=>root.innerHTML='';root.querySelector('#authSignin')?.addEventListener('click',()=>showAuthModal('signin'));root.querySelector('#authSignup')?.addEventListener('click',()=>showAuthModal('signup'));root.querySelector('#authReset')?.addEventListener('click',()=>showAuthModal('reset'));submit.onclick=async()=>{try{submit.disabled=true;submit.textContent=isSignUp?'Creating…':isReset?'Sending…':'Signing in…';error.textContent='';const email=root.querySelector('#authEmail').value.trim(),password=root.querySelector('#authPassword')?.value||'';if(!email)throw Error('Email is required');state.cloud.status=isReset?'Sending reset…':'Signing in…';renderCloudHeader();if(isReset){const {error:e}=await supabaseClient.auth.resetPasswordForEmail(email,{redirectTo:authRedirectUrl()});if(e)throw e;toast('Password reset email sent');root.innerHTML='';return}const result=isSignUp?await supabaseClient.auth.signUp({email,password,options:{emailRedirectTo:authRedirectUrl()}}):await supabaseClient.auth.signInWithPassword({email,password});if(result.error)throw result.error;state.cloud.session=result.data.session;state.cloud.user=result.data.user;if(!state.cloud.session&&isSignUp){toast('Account created. Check your email to confirm it.');root.innerHTML='';return}await loadSupabaseProfiles(true);root.innerHTML='';toast(isSignUp?'Account ready':'Signed in')}catch(e){error.textContent=e.message;state.cloud.status='SIGNED OUT — sign in to sync';renderCloudHeader();submit.disabled=false;submit.textContent=isSignUp?'Create account':isReset?'Send reset email':'Sign in'}}}
function showPasswordUpdateModal(){const root=document.querySelector('#modalRoot');root.innerHTML=`<div class="modal-backdrop"><section class="modal auth-modal"><p class="eyebrow">Password reset</p><h2>Choose a new password</h2><label class="field">New password<input id="newPassword" class="form-control" type="password" autocomplete="new-password"></label><div class="modal-actions"><button class="btn" id="saveNewPassword">Update password</button><button class="btn ghost" id="cancelNewPassword">Cancel</button></div><p class="form-error" id="passwordError"></p></section></div>`;root.querySelector('#cancelNewPassword').onclick=()=>root.innerHTML='';root.querySelector('#saveNewPassword').onclick=async()=>{const password=root.querySelector('#newPassword').value,error=root.querySelector('#passwordError');try{if(password.length<6)throw Error('Use at least 6 characters');const {error:e}=await supabaseClient.auth.updateUser({password});if(e)throw e;root.innerHTML='';toast('Password updated')}catch(e){error.textContent=e.message}}}
async function waitForGoogle(){for(let i=0;i<40;i++){if(window.google?.accounts?.oauth2)return;if(i===0&&!document.querySelector('script[src*="accounts.google.com/gsi/client"]')){const s=document.createElement('script');s.src='https://accounts.google.com/gsi/client';s.async=true;s.defer=true;document.head.appendChild(s)}await new Promise(r=>setTimeout(r,125))}throw Error('Google sign-in did not load.')}
async function cloudAuth(promptMode,timeoutMs=12000){await waitForGoogle();return new Promise((resolve,reject)=>{let settled=false;let timer;const finish=(fn,value)=>{if(settled)return;settled=true;clearTimeout(timer);fn(value)};state.cloud.tokenClient ||= google.accounts.oauth2.initTokenClient({client_id:GOOGLE_CLIENT_ID,scope:DRIVE_SCOPE,include_granted_scopes:true,callback:res=>{if(res.error){finish(reject,Error(res.error));return}state.cloud.token=res.access_token;state.cloud.tokenExpiresAt=Date.now()+((Number(res.expires_in)||3600)-60)*1000;finish(resolve,res.access_token)}});timer=setTimeout(()=>finish(reject,Error('Google Drive import could not connect')),timeoutMs);state.cloud.tokenClient.requestAccessToken({prompt:promptMode??'consent'})})}
async function driveFetch(path,options={}){const response=await fetch(`https://www.googleapis.com/drive/v3/${path}`,{...options,headers:{Authorization:`Bearer ${state.cloud.token}`,...(options.headers||{})}});if(!response.ok)throw Error(`Google Drive import failed (${response.status})`);return response}
async function findCloudFile(){const q=encodeURIComponent(`name='${CLOUD_FILE_NAME}' and 'appDataFolder' in parents and trashed=false`),response=await driveFetch(`files?spaces=appDataFolder&fields=files(id,name,modifiedTime)&q=${q}`),data=await response.json();return data.files?.[0]||null}
function multipartBody(metadata,json){const boundary='droid-archives-boundary';return{boundary,body:`--${boundary}\r\nContent-Type: application/json; charset=UTF-8\r\n\r\n${JSON.stringify(metadata)}\r\n--${boundary}\r\nContent-Type: application/json; charset=UTF-8\r\n\r\n${JSON.stringify(json,null,2)}\r\n--${boundary}--`}}
async function readCloudDoc(fileId){const response=await driveFetch(`files/${fileId}?alt=media`);return normalizeCloudDoc(await response.json())}
async function importGoogleDriveProfiles(){try{if(!cloudConnected()){toast('Sign in with Supabase first');return}state.cloud.status='Importing Google Drive profiles…';renderCloudHeader();await cloudAuth('consent',30000);const file=await findCloudFile();if(!file){toast('No Google Drive save found');return}const imported=await readCloudDoc(file.id),current=state.cloud.doc,seen=new Set(current.profiles.map(p=>p.id));imported.profiles.forEach((profile,index)=>{const id=seen.has(profile.id)?cloudId():profile.id;seen.add(id);current.profiles.push({...profile,id,name:`Google: ${profile.name||`Profile ${index+1}`}`})});if(imported.profiles.length&&!current.activeProfileId)current.activeProfileId=current.profiles[0].id;await cloudSaveNow();toast(`Imported ${imported.profiles.length} Google profile${imported.profiles.length===1?'':'s'}`)}catch(e){state.cloud.status=e.message;renderCloudHeader();toast(e.message)}}
function addCloudProfile(){const doc=activeProfileDoc(),root=document.querySelector('#modalRoot');root.innerHTML=`<div class="modal-backdrop"><section class="modal" role="dialog" aria-modal="true"><p class="eyebrow">Profile setup</p><h2>Create new profile</h2><p class="picker-hint">Copy your current Base/settings, or start fresh. Droidex always starts empty for a new profile.</p><label class="field">Profile name<input id="newProfileName" class="form-control" value="New profile"></label><p class="form-error" id="newProfileError"></p><div class="modal-actions"><button class="btn" id="copyProfile">Copy Base/settings</button><button class="btn secondary" id="blankProfile">Start blank profile</button><button class="btn ghost" id="cancelProfile">Cancel</button></div></section></div>`;const nameInput=root.querySelector('#newProfileName'),error=root.querySelector('#newProfileError'),create=mode=>{const name=nameInput.value.trim();if(!name){error.textContent='Profile name is required';return}if(cloudConnected())updateActiveCloudProfile();else updateActiveLocalProfile();const id=cloudId(),data=mode==='copy'?cloneProfileBaseOnly(profileDataFromState()):blankProfileData();doc.profiles.push({id,name,updatedAt:new Date().toISOString(),data});state.cloud.activeProfileId=id;doc.activeProfileId=id;applyProfileData(data);save();root.innerHTML='';route();toast(`Profile created: ${name}`)};root.querySelector('#copyProfile').onclick=()=>create('copy');root.querySelector('#blankProfile').onclick=()=>create('blank');root.querySelector('#cancelProfile').onclick=()=>root.innerHTML='';nameInput.focus();nameInput.select()}
function renameCloudProfile(){const profile=activeProfile();if(!profile)return;const name=prompt('Rename profile:',profile.name)?.trim();if(!name)return;profile.name=name;save();route();toast('Profile renamed')}
function deleteCloudProfile(){const doc=activeProfileDoc(),profile=activeProfile();if(!profile)return;if(doc.profiles.length<=1){toast('You need at least one profile');return}if(!confirm(`Delete profile "${profile.name}"?`))return;doc.profiles=doc.profiles.filter(p=>p.id!==profile.id);state.cloud.activeProfileId=doc.profiles[0].id;doc.activeProfileId=state.cloud.activeProfileId;applyProfileData(activeProfile().data);save();route();toast('Profile deleted')}
function switchCloudProfile(id){const doc=activeProfileDoc();if(!doc||id===state.cloud.activeProfileId)return;if(cloudConnected())updateActiveCloudProfile();else updateActiveLocalProfile();state.cloud.activeProfileId=id;doc.activeProfileId=id;applyProfileData(activeProfile().data);save();route();toast(`Switched to ${activeProfile()?.name||'profile'}`)}
function cloudSidebarHtml(){const connected=cloudConnected(),doc=activeProfileDoc(),profiles=doc?.profiles||[],active=activeProfile(),needsLogin=state.cloud.enabled&&!connected&&!state.cloud.reconnecting,reconnecting=state.cloud.enabled&&!connected&&state.cloud.reconnecting,setup=!supabaseReady();return `<div class="cloud-panel ${needsLogin||setup?'cloud-needs-login':''} ${reconnecting?'cloud-reconnecting':''}"><p class="side-title">${connected?'Cloud save':'Profiles'}</p><label class="side-field">Profile<select id="cloudProfileSelect">${profiles.map(p=>`<option value="${p.id}" ${p.id===state.cloud.activeProfileId?'selected':''}>${p.name}</option>`).join('')}</select></label><small class="cloud-status">${setup?'Supabase setup needed':connected?state.cloud.status:reconnecting?'Restoring Supabase session…':needsLogin?'SIGNED OUT — changes save locally only':'Local profiles'}${active?` · ${active.name}`:''}</small>${setup?'<div class="cloud-warning">Add data/supabase-config.json to enable account sync.</div>':needsLogin?'<div class="cloud-warning">You are signed out. Local changes will not sync until you sign in.</div>':''}<div class="cloud-actions">${connected?'<button class="btn secondary" id="cloudSyncNow">Sync now</button><button class="btn secondary" id="cloudImportGoogle">Import Google Drive profiles</button>':reconnecting?'<button class="btn secondary" disabled>Restoring…</button>':'<button class="btn secondary cloud-connect" id="cloudConnect">Sign in</button><button class="btn secondary" id="cloudCreateAccount">Create account</button><button class="btn secondary" id="cloudResetPassword">Reset password</button>'}<button class="btn secondary" id="cloudNewProfile">New profile</button><button class="btn secondary" id="cloudRenameProfile">Rename</button><button class="btn danger" id="cloudDeleteProfile">Delete</button>${connected?'<button class="btn ghost" id="cloudSignOut">Sign out</button>':''}</div><div class="side-rule"></div></div>`}
function attachCloudSidebarHandlers(root=document){root.querySelector('#cloudConnect')?.addEventListener('click',()=>showAuthModal('signin'));root.querySelector('#cloudCreateAccount')?.addEventListener('click',()=>showAuthModal('signup'));root.querySelector('#cloudResetPassword')?.addEventListener('click',()=>showAuthModal('reset'));root.querySelector('#cloudSyncNow')?.addEventListener('click',()=>cloudSaveNow().catch(e=>toast(e.message)));root.querySelector('#cloudImportGoogle')?.addEventListener('click',importGoogleDriveProfiles);root.querySelector('#cloudNewProfile')?.addEventListener('click',addCloudProfile);root.querySelector('#cloudRenameProfile')?.addEventListener('click',renameCloudProfile);root.querySelector('#cloudDeleteProfile')?.addEventListener('click',deleteCloudProfile);root.querySelector('#cloudSignOut')?.addEventListener('click',signOutCloud);root.querySelector('#cloudProfileSelect')?.addEventListener('change',e=>switchCloudProfile(e.target.value))}
function renderCloudHeader(){const host=document.querySelector('#headerCloud');if(!host)return;const connected=cloudConnected(),doc=activeProfileDoc(),profiles=doc?.profiles||[],active=activeProfile(),needsLogin=state.cloud.enabled&&!connected&&!state.cloud.reconnecting,reconnecting=state.cloud.enabled&&!connected&&state.cloud.reconnecting,setup=!supabaseReady();host.innerHTML=`<button class="cloud-menu-button ${connected?'connected':''} ${needsLogin||setup?'needs-login':''} ${reconnecting?'reconnecting':''}" id="cloudMenuButton" aria-label="Cloud save menu" aria-expanded="false" title="${setup?'Supabase setup needed':connected?'Cloud save connected':reconnecting?'Restoring Supabase session':needsLogin?'Signed out':'Local profiles'}">☰${needsLogin||setup?'!':''}</button><div class="cloud-dropdown ${needsLogin||setup?'cloud-needs-login':''} ${reconnecting?'cloud-reconnecting':''}" id="cloudDropdown" hidden>${cloudSidebarHtml().replace('<div class="side-rule"></div>','')}</div>`;const button=host.querySelector('#cloudMenuButton'),dropdown=host.querySelector('#cloudDropdown');button.onclick=e=>{e.stopPropagation();dropdown.hidden=!dropdown.hidden;button.setAttribute('aria-expanded',String(!dropdown.hidden))};dropdown.onclick=e=>e.stopPropagation();attachCloudSidebarHandlers(host)}
function renderBaseSidebar(rerender){const host=document.querySelector('#baseSidebarControls');host.innerHTML=`${cloudSidebarHtml()}<p class="side-title">Base settings</p><label class="side-field">Base multiplier<input id="sideMultiplier" type="number" min="0" step="0.1" value="${state.multiplier}"><small class="flawless-bonus">${flawlessCount()} flawless tracked · ${effectiveMultiplier().toFixed(2)}× total</small></label><label class="side-field">Super rebirth<select id="sideCycle">${Object.keys(state.rebirths).map(c=>`<option value="${c}" ${Number(c)===state.cycle?'selected':''}>Cycle ${Number(c)+1}</option>`).join('')}</select></label><label class="side-field">Current rebirth<select id="sideRebirth">${Array.from({length:28},(_,n)=>`<option ${n===state.rebirth?'selected':''}>${n}</option>`).join('')}</select></label><button class="btn danger super-rebirth-button" id="superRebirthButton">Super rebirth</button><div class="side-rule"></div>`;attachCloudSidebarHandlers(host);host.querySelector('#sideMultiplier').onchange=e=>{state.multiplier=Number(e.target.value)||0;save();rerender()};host.querySelector('#sideCycle').onchange=e=>{state.cycle=Number(e.target.value);save();rerender()};host.querySelector('#sideRebirth').onchange=e=>{state.rebirth=Number(e.target.value);save();rerender()};host.querySelector('#superRebirthButton').onclick=()=>showSuperRebirthConfirm(rerender)}
function showSlotPicker(station,onDone,slot){const root=document.querySelector('#modalRoot'),allowed=state.droids;root.innerHTML=`<div class="modal-backdrop"><section class="modal slot-picker" role="dialog" aria-modal="true"><p class="eyebrow">${station==='BUILD'?'Universal build':station} slot</p><h2>Choose any droid</h2><p class="picker-hint">Any droid can use this station. Matching the droid’s type grants it +10% credits.</p><input id="slotSearch" class="form-control picker-search" placeholder="Search droids…" autofocus><div id="pickerResults" class="picker-results"></div><button class="btn ghost" id="cancelPicker">Cancel</button></section></div>`;const draw=()=>{const q=root.querySelector('#slotSearch').value.toLowerCase();root.querySelector('#pickerResults').innerHTML=allowed.filter(d=>d.name.toLowerCase().includes(q)).map(d=>`<button class="picker-droid ${d.type===station?'type-match':''}" data-name="${d.name}"><span>${picture(d)}</span><b>${d.name}</b><small>${d.rarity} · ${d.type}${d.type===station?' · +10%':''}</small></button>`).join('')||'<p class="roster-empty">No matching droids.</p>';root.querySelectorAll('.picker-droid').forEach(b=>b.onclick=()=>showVariantChoice(b.dataset.name,station,onDone,slot))};root.querySelector('#slotSearch').oninput=draw;root.querySelector('#cancelPicker').onclick=()=>root.innerHTML='';draw()}
function showVariantChoice(name,station,onDone,slot){const root=document.querySelector('#modalRoot'),d=state.droids.find(x=>x.name===name);root.innerHTML=`<div class="modal-backdrop"><section class="modal"><p class="eyebrow">${station} slot</p><h2>Add ${name}</h2><div class="variant-choice">${VARIANTS.map(v=>`<button data-variant="${v}">${picture(d,v)}<strong>${v[0]+v.slice(1).toLowerCase()}</strong><small>${fmt(d.variants[v].income)}/s</small></button>`).join('')}</div><button class="btn ghost" id="backToPicker">Back</button></section></div>`;root.querySelectorAll('[data-variant]').forEach(b=>b.onclick=()=>{commitOwned(name,b.dataset.variant,1,station,slot);root.innerHTML='';onDone()});root.querySelector('#backToPicker').onclick=()=>showSlotPicker(station,onDone,slot)}
function showBlueprintPicker(slot,onDone){const root=document.querySelector('#modalRoot');root.innerHTML=`<div class="modal-backdrop"><section class="modal slot-picker"><p class="eyebrow">Blueprint Storage</p><h2>Store a blueprint</h2><p class="picker-hint">Blueprints live here until you craft them into an open Build slot.</p><input id="blueprintSearch" class="form-control picker-search" placeholder="Search droids…" autofocus><div id="blueprintResults" class="picker-results"></div><button class="btn ghost" id="cancelBlueprint">Cancel</button></section></div>`;const draw=()=>{const q=root.querySelector('#blueprintSearch').value.toLowerCase();root.querySelector('#blueprintResults').innerHTML=state.droids.filter(d=>d.name.toLowerCase().includes(q)).map(d=>`<button class="picker-droid" data-name="${d.name}"><span>${picture(d)}</span><b>${d.name}</b><small>${d.rarity} · blueprint</small></button>`).join('')||'<p class="roster-empty">No matching droids.</p>';root.querySelectorAll('.picker-droid').forEach(b=>b.onclick=()=>showBlueprintVariantChoice(b.dataset.name,slot,onDone))};root.querySelector('#blueprintSearch').oninput=draw;root.querySelector('#cancelBlueprint').onclick=()=>root.innerHTML='';draw()}
function showBlueprintVariantChoice(name,slot,onDone){const root=document.querySelector('#modalRoot'),d=state.droids.find(x=>x.name===name);root.innerHTML=`<div class="modal-backdrop"><section class="modal"><p class="eyebrow">Blueprint Storage</p><h2>Store ${name} blueprint</h2><div class="variant-choice">${VARIANTS.map(v=>`<button data-variant="${v}">${picture(d,v)}<strong>${variantLabel(v)}</strong><small>Blueprint</small></button>`).join('')}</div><button class="btn ghost" id="backToBlueprintPicker">Back</button></section></div>`;root.querySelectorAll('[data-variant]').forEach(b=>b.onclick=()=>{addBlueprint(name,b.dataset.variant,slot);root.innerHTML='';onDone()});root.querySelector('#backToBlueprintPicker').onclick=()=>showBlueprintPicker(slot,onDone)}
function baseExport(){return{app:'Droid Archives',version:4,exportedAt:new Date().toISOString(),base:{owned:state.owned,blueprints:state.blueprints,droidex:state.droidex,novaUpgrades:state.novaUpgrades,multiplier:state.multiplier,cycle:state.cycle,rebirth:state.rebirth,loungePurchased:state.loungePurchased,novaLevel:state.novaLevel}}}
function droidexExport(){return{app:'Droid Archives',version:3,exportedAt:new Date().toISOString(),droidex:state.droidex}}
function validateDroidexImport(value){const rows=normalizeDroidRows(value?.droidex??value?.base?.droidex??value);if(!Array.isArray(rows))throw Error('This file does not contain a valid Droidex.');const validNames=new Set(state.droids.map(d=>d.name)),flawlessNames=new Set(rows.filter(x=>x?.flawless).map(x=>x.name)),entries=new Map();for(const row of rows){const d=state.droids.find(x=>x.name===row?.name);if(!validNames.has(row?.name)||!VARIANTS.includes(row?.variant)||isIconic(d)&&row.variant!=='DEFAULT')throw Error(`Invalid Droidex entry: ${row?.name||'unknown'}.`);entries.set(`${row.name}:${row.variant}`,{name:row.name,variant:row.variant,flawless:!isIconic(d)&&flawlessNames.has(row.name)})}return[...entries.values()]}
